    "private static final void encodeQuotedPrintable(int b, ByteArrayOutputStream buffer) {
        buffer.write(ESCAPE_CHAR);
        char hex1 = Character.toUpperCase(Character.forDigit((b >> 4) & 0xF, 16));
        char hex2 = Character.toUpperCase(Character.forDigit(b & 0xF, 16));
        buffer.write(hex1);
        buffer.write(hex2);
    }",
    "public static final byte[] encodeQuotedPrintable(BitSet printable, byte[] bytes) {
        if (bytes == null) {
            return null;
        }
        if (printable == null) {
            printable = PRINTABLE_CHARS;
        }
        final int MAX_LINE_LENGTH = 76;
        ByteArrayOutputStream buffer = new ByteArrayOutputStream();
        int pos = 0; // current line position
        for (int i = 0; i < bytes.length; i++) {
            int b = bytes[i] & 0xFF;
            boolean isPrintable = printable.get(b) && b != '=';
            if (isPrintable) {
                boolean isWhitespace = (b == ' ' || b == '\t');
                if (isWhitespace) {
                    // whitespace at end of line must be encoded
                    if (pos == MAX_LINE_LENGTH - 1) {
                        // need to encode; ensure room
                        if (pos + 3 > MAX_LINE_LENGTH) {
                            buffer.write('=');
                            buffer.write('\r');
                            buffer.write('\n');
                            pos = 0;
                        }
                        encodeQuotedPrintable(b, buffer);
                        pos += 3;
                    } else {
                        // safe to write literally
                        if (pos + 1 > MAX_LINE_LENGTH) {
                            buffer.write('=');
                            buffer.write('\r');
                            buffer.write('\n');
                            pos = 0;
                        }
                        buffer.write(b);
                        pos += 1;
                    }
                } else {
                    if (pos + 1 > MAX_LINE_LENGTH) {
                        buffer.write('=');
                        buffer.write('\r');
                        buffer.write('\n');
                        pos = 0;
                    }
                    buffer.write(b);
                    pos += 1;
                }
            } else {
                // needs encoding (including '=')
                if (pos + 3 > MAX_LINE_LENGTH) {
                    buffer.write('=');
                    buffer.write('\r');
                    buffer.write('\n');
                    pos = 0;
                }
                encodeQuotedPrintable(b, buffer);
                pos += 3;
            }
        }
        return buffer.toByteArray();
    }",
    "public static final byte[] decodeQuotedPrintable(byte[] bytes) throws DecoderException {
        if (bytes == null) {
            return null;
        }
        ByteArrayOutputStream buffer = new ByteArrayOutputStream();
        for (int i = 0; i < bytes.length; i++) {
            int b = bytes[i] & 0xFF;
            // Skip raw CR and LF (not encoded and not part of soft line break)
            if (b == '\r' || b == '\n') {
                continue;
            }
            if (b == ESCAPE_CHAR) {
                // handle soft line breaks and hex encodings
                if (i + 1 >= bytes.length) {
                    throw new DecoderException("Invalid quoted-printable encoding");
                }
                int next = bytes[i + 1] & 0xFF;
                // soft line break "=\r\n" or tolerant "=\n" or "=\r"
                if (next == '\r') {
                    if (i + 2 < bytes.length && (bytes[i + 2] & 0xFF) == '\n') {
                        i += 2; // skip =\r\n
                    } else {
                        i += 1; // skip =\r (tolerant)
                    }
                    continue;
                } else if (next == '\n') {
                    i += 1; // skip =\n (tolerant)
                    continue;
                } else {
                    // must be two hex digits
                    if (i + 2 >= bytes.length) {
                        throw new DecoderException("Invalid quoted-printable encoding");
                    }
                    try {
                        int u = Utils.digit16(bytes[++i]);
                        int l = Utils.digit16(bytes[++i]);
                        buffer.write((u << 4) + l);
                    } catch (RuntimeException e) {
                        throw new DecoderException("Invalid quoted-printable encoding", e);
                    }
                }
            } else {
                buffer.write(b);
            }
        }
        return buffer.toByteArray();
    }"
